// Applies the Supabase-powered club page updates to your project.
// Run this from your project root: node apply-supabase-pages.js

const fs = require('fs');
const path = require('path');

const files = {
  "components/ClubMap.tsx": "",
  "components/ClubMapLoader.tsx": "",
  "app/manchester-city/page.tsx": "",
  "app/arsenal/page.tsx": "",
  "app/aston-villa/page.tsx": "",
  "app/bournemouth/page.tsx": "",
  "app/brentford/page.tsx": "",
  "app/brighton/page.tsx": "",
  "app/celtic/page.tsx": "",
  "app/chelsea/page.tsx": "",
  "app/coventry/page.tsx": "",
  "app/crystal-palace/page.tsx": "",
  "app/everton/page.tsx": "",
  "app/fulham/page.tsx": "",
  "app/hull/page.tsx": "",
  "app/ipswich/page.tsx": "",
  "app/leeds/page.tsx": "",
  "app/liverpool/page.tsx": "",
  "app/manchester-united/page.tsx": "",
  "app/newcastle/page.tsx": "",
  "app/nottingham-forest/page.tsx": "",
  "app/rangers/page.tsx": "",
  "app/spurs/page.tsx": "",
  "app/sunderland/page.tsx": "",
};

let count = 0;
for (const [relPath, b64] of Object.entries(files)) {
  const fullPath = path.join(__dirname, relPath);
  fs.mkdirSync(path.dirname(fullPath), { recursive: true });
  fs.writeFileSync(fullPath, Buffer.from(b64, 'base64').toString('utf-8'));
  console.log('Wrote', relPath);
  count++;
}
console.log(`\nDone. ${count} files written.`);